import React, { useState } from 'react';

const BandcampWidget = ({ url, id, type }) => (
  <iframe
    style={{ border: 0, width: '350px', height: type === 'album' ? '470px' : '120px', marginBottom: '10px' }}
    src={`https://bandcamp.com/EmbeddedPlayer/${type}=${id}/size=large/bgcol=ffffff/linkcol=0687f5/tracklist=false/transparent=true/`}
    seamless
  >
    <a href={url}>View on Bandcamp</a>
  </iframe>
);

const SetlistCreator = () => {
  const [newTrackUrl, setNewTrackUrl] = useState('');
  const [setlist, setSetlist] = useState([]);
  const [recommendations, setRecommendations] = useState([]);
  const [minBpm, setMinBpm] = useState(120);
  const [maxBpm, setMaxBpm] = useState(140);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  const getBandcampId = async (url) => {
    const response = await fetch('http://127.0.0.1:8000/get-bandcamp-id', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url }),
    });
    if (!response.ok) throw new Error('Failed to get Bandcamp ID');
    return await response.json();
  };

  const addTrack = async () => {
    if (newTrackUrl.trim()) {
      try {
        const { id, type } = await getBandcampId(newTrackUrl.trim());
        setSetlist([...setlist, { url: newTrackUrl.trim(), id, type }]);
        setNewTrackUrl('');
      } catch (error) {
        setError('Failed to add track. Please check the URL and try again.');
      }
    }
  };

  const removeTrack = (index) => {
    const newSetlist = setlist.filter((_, i) => i !== index);
    setSetlist(newSetlist);
  };

  const generateRecommendations = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await fetch('http://127.0.0.1:8000/generate-recommendations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          tracks: setlist.map(track => ({ url: track.url })),
          min_bpm: minBpm,
          max_bpm: maxBpm,
        }),
      });

      if (!response.ok) throw new Error('Failed to generate recommendations');

      const data = await response.json();
      const recommendationsWithIds = await Promise.all(
        data.map(async (rec) => {
          const { id, type } = await getBandcampId(rec.url);
          return { ...rec, id, type };
        })
      );
      setRecommendations(recommendationsWithIds);
    } catch (error) {
      console.error('Error generating recommendations:', error);
      setError('Failed to generate recommendations. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div style={{ display: 'flex', maxWidth: '1200px', margin: '0 auto', padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <div style={{ flex: 1, marginRight: '20px' }}>
        <h1 style={{ fontSize: '24px', marginBottom: '20px', color: '#333' }}>Setlist Creator</h1>

        <div style={{ marginBottom: '20px' }}>
          <input
            type="text"
            value={newTrackUrl}
            onChange={(e) => setNewTrackUrl(e.target.value)}
            placeholder="Enter Bandcamp track or album URL"
            style={{ width: '100%', padding: '10px', marginBottom: '10px', borderRadius: '4px', border: '1px solid #ccc' }}
          />
          <button
            onClick={addTrack}
            style={{ padding: '10px 20px', backgroundColor: '#4CAF50', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
          >
            Add to Setlist
          </button>
        </div>

        <div style={{ marginBottom: '20px' }}>
          <input
            type="number"
            value={minBpm}
            onChange={(e) => setMinBpm(parseInt(e.target.value))}
            placeholder="Min BPM"
            style={{ width: '80px', padding: '10px', marginRight: '10px', borderRadius: '4px', border: '1px solid #ccc' }}
          />
          <input
            type="number"
            value={maxBpm}
            onChange={(e) => setMaxBpm(parseInt(e.target.value))}
            placeholder="Max BPM"
            style={{ width: '80px', padding: '10px', borderRadius: '4px', border: '1px solid #ccc' }}
          />
        </div>

        <button
          onClick={generateRecommendations}
          style={{ padding: '10px 20px', backgroundColor: '#008CBA', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
        >
          Generate Recommendations
        </button>
      </div>

      <div style={{ flex: 1 }}>
        <h2 style={{ fontSize: '20px', marginBottom: '10px', color: '#333' }}>Your Setlist:</h2>
        {setlist.map((track, index) => (
          <div key={index} style={{ marginBottom: '20px' }}>
            <BandcampWidget url={track.url} id={track.id} type={track.type} />
            <button
              onClick={() => removeTrack(index)}
              style={{ padding: '5px 10px', backgroundColor: '#f44336', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
            >
              Remove
            </button>
          </div>
        ))}

        {isLoading && <p>Loading recommendations...</p>}
        {error && <p style={{ color: 'red' }}>{error}</p>}

        <h2 style={{ fontSize: '20px', marginTop: '20px', marginBottom: '10px', color: '#333' }}>Recommendations:</h2>
        {recommendations.map((rec, index) => (
          <div key={index} style={{ marginBottom: '20px' }}>
            <BandcampWidget url={rec.url} id={rec.id} type={rec.type} />
          </div>
        ))}
      </div>
    </div>
  );
};

export default SetlistCreator;
